// Check if this is Phase 1 complete and prepare for Phase 2
const agentOutput = $json;
const workflowContext = $('Parse Phase 1 Instructions').first().json.workflowContext;

// Parse agent results
let agentResults;
try {
  const outputText = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);
  const jsonMatch = outputText.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    agentResults = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in agent output');
  }
} catch (error) {
  console.error('Error parsing agent results:', error.message);
  agentResults = {
    error: error.message,
    status: { success: false, next_phase: 'error' }
  };
}

// Check if this was Phase 1 (categorization)
if (agentResults.phase === 'phase1_categorization_complete') {
  // This is Phase 1 complete, prepare Phase 2 instructions
  const categorizedIdeas = agentResults.results?.ideas_processed || [];

  // Prepare Phase 2 context
  const phase2Context = {
    sessionId: workflowContext.sessionId,
    phase1Results: agentResults,
    categorizedIdeas,
    targetDatabases: workflowContext.targetDatabases,
    phase: 'phase2_preparation'
  };

  return [{
    phase2Ready: true,
    phase1Complete: true,
    phase2Context,
    categorizedIdeas,
    nextAction: 'prepare_phase2'
  }];
} else if (agentResults.phase === 'phase2_database_creation_complete') {
  // This is Phase 2 complete, workflow finished
  return [{
    workflowComplete: true,
    phase1Results: agentResults.phase1_summary || {},
    phase2Results: agentResults.results || {},
    finalStatus: agentResults.status || { success: false },
    nextAction: 'workflow_complete'
  }];
} else {
  // Unknown phase or error
  return [{
    error: true,
    message: `Unknown phase: ${agentResults.phase}`,
    agentOutput: agentResults,
    nextAction: 'error_review'
  }];
}

// Parse Phase 2 Instructions
const directorResponse = $json;
const phase2Context = $('🔄 Workflow Controller').first().json.phase2Context;

const instructionData = directorResponse.data;

if (!instructionData || !instructionData.instruction) {
  return [{
    instructionText: "Error: No valid Phase 2 instructions received",
    error: true,
    task_id: "phase2_error"
  }];
}

const instruction = instructionData.instruction;
const categorizedIdeas = phase2Context.categorizedIdeas || [];

let instructionText = '';
instructionText += `# PHASE 2: DATABASE ITEM CREATION\n\n`;
instructionText += `## WORKFLOW STATUS\n`;
instructionText += `- ✅ Phase 1: Categorization Complete (${categorizedIdeas.length} ideas processed)\n`;
instructionText += `- 🔄 Phase 2: Database Creation In Progress\n`;
instructionText += `- Session ID: ${phase2Context.sessionId}\n\n`;

instructionText += `## OBJECTIVE\n`;
instructionText += `${instruction.objective}\n\n`;

instructionText += `## TARGET DATABASES\n`;
Object.entries(phase2Context.targetDatabases).forEach(([type, id]) => {
  const count = categorizedIdeas.filter(i => i.categorization?.database === type).length;
  instructionText += `- **${type.toUpperCase()}** (${id}): ${count} items to create\n`;
});
instructionText += '\n';

instructionText += `## CATEGORIZED IDEAS TO CREATE\n`;
categorizedIdeas.forEach((idea, index) => {
  if (idea.categorization) {
    instructionText += `### ${index + 1}. ${idea.title}\n`;
    instructionText += `- **Target**: ${idea.categorization.database}\n`;
    instructionText += `- **Category**: ${idea.categorization.category || 'Not specified'}\n`;
    instructionText += `- **Priority**: ${idea.categorization.priority || 'Medium'}\n`;
    instructionText += `- **Tags**: [${(idea.categorization.tags || []).join(', ')}]\n\n`;
  }
});

instructionText += `## EXECUTION PLAN\n`;
instructionText += `1. For each categorized idea:\n`;
instructionText += `   - Get database schema for target database\n`;
instructionText += `   - Create database item with proper properties\n`;
instructionText += `   - Verify creation success\n`;
instructionText += `2. Return complete results\n\n`;

instructionText += `## REQUIRED OUTPUT FORMAT\n`;
instructionText += `Return JSON with operations_completed array and summary.\n`;

return [{
  instructionText,
  task_id: instructionData.task_id,
  phase: 'phase2_database_creation',
  categorizedIdeas,
  targetDatabases: phase2Context.targetDatabases
}];

// Final Results Analysis
const workflowResults = $json;
const workflowContext = $('Initialize Workflow Context').first().json.workflowContext;

const startTime = new Date(workflowContext.startTime);
const endTime = new Date();
const totalDuration = endTime.getTime() - startTime.getTime();

let analysis = {};

if (workflowResults.workflowComplete) {
  analysis = {
    status: 'SUCCESS',
    workflow_complete: true,
    session_id: workflowContext.sessionId,
    total_duration_ms: totalDuration,
    phase1_results: workflowResults.phase1Results,
    phase2_results: workflowResults.phase2Results,
    final_status: workflowResults.finalStatus,
    summary: {
      ideas_processed: workflowResults.phase1Results?.results?.ideas_processed?.length || 0,
      database_items_created: workflowResults.phase2Results?.operations_completed?.length || 0,
      success_rate: workflowResults.finalStatus?.success ? '100%' : 'Partial'
    }
  };
} else if (workflowResults.error) {
  analysis = {
    status: 'ERROR',
    workflow_complete: false,
    session_id: workflowContext.sessionId,
    total_duration_ms: totalDuration,
    error_message: workflowResults.message,
    debug_info: workflowResults.agentOutput
  };
} else {
  analysis = {
    status: 'UNKNOWN',
    workflow_complete: false,
    session_id: workflowContext.sessionId,
    total_duration_ms: totalDuration,
    raw_results: workflowResults
  };
}

return [analysis];
